<template><div class="page"><div class="toolbar"><h2>帮助中心</h2><el-input v-model="keyword" placeholder="搜索帮助文章" style="width:260px" clearable @keyup.enter="search"/><el-select v-model="category" clearable placeholder="分类" @change="load"><el-option label="入门" value="入门"/><el-option label="声音" value="声音"/><el-option label="TTS" value="TTS"/><el-option label="直播" value="直播"/></el-select><el-button type="primary" @click="search">搜索</el-button></div><el-row :gutter="16"><el-col :span="8" v-for="a in articles" :key="a.id"><el-card style="margin-bottom:16px"><h3>{{a.title}}</h3><p class="muted">{{a.category}}</p><p>{{(a.content||'').slice(0,70)}}...</p><el-button link type="primary" @click="open(a.id)">查看详情</el-button></el-card></el-col></el-row><el-empty v-if="!articles.length" description="暂无文章"/><el-dialog v-model="dialog" :title="detail?.title" width="720px"><div style="white-space:pre-wrap;line-height:1.8">{{detail?.content}}</div></el-dialog></div></template>
<script setup>import { ref,onMounted } from 'vue';import { getHelpArticles,getHelpArticle,searchHelp } from '../api/help';const articles=ref([]),keyword=ref(''),category=ref(''),dialog=ref(false),detail=ref(null);async function load(){articles.value=await getHelpArticles(category.value?{category:category.value}:undefined).catch(()=>[])||[]}async function search(){articles.value=keyword.value?await searchHelp(keyword.value).catch(()=>[])||[]:await getHelpArticles().catch(()=>[])||[]}async function open(id){detail.value=await getHelpArticle(id);dialog.value=true}onMounted(load)</script>
